import type { Block, Inline, Node } from '@contentful/rich-text-types';
import { get, set } from 'json-pointer';

import { combine } from './encode.js';
import type { CPAMappings, GraphQLMappings, SourceMapMetadata } from './types.js';

export const encodeRichTextValue = ({
  pointer,
  mappings,
  data,
  hiddenStrings,
}: {
  pointer: string;
  mappings: CPAMappings | GraphQLMappings;
  data: Node;
  hiddenStrings: SourceMapMetadata;
}) => {
  const source = mappings[pointer];

  // Only proceed with mapping if we have a valid source
  if (source) {
    // We can now safely delete the original pointer as we've preserved the source
    delete mappings[pointer];

    const textNodes = findRichTextNodes(data, pointer);
    for (const textNode of textNodes) {
      mappings[textNode] = source;
      const currentTextNodeValue = get(data, textNode);
      const encodedValue = combine(currentTextNodeValue, hiddenStrings);
      set(data, textNode, encodedValue);
    }
  } else {
    // If there's no source mapping, just encode the text nodes without creating mappings
    const textNodes = findRichTextNodes(data, pointer);
    for (const textNode of textNodes) {
      const currentTextNodeValue = get(data, textNode);
      const encodedValue = combine(currentTextNodeValue, hiddenStrings);
      set(data, textNode, encodedValue);
    }
  }
};

function isNode(node: Node): node is Block | Inline {
  return 'content' in node && !!node.content;
}

const findRichTextNodes = (data: Node, currentPath = ''): string[] => {
  const textNodes = [];
  const node = get(data, currentPath);

  if (isNode(node)) {
    for (let i = 0; i < node.content.length; i++) {
      if (node.content[i].nodeType === 'text') {
        textNodes.push(`${currentPath}/content/${i}/value`);
      } else {
        textNodes.push(...findRichTextNodes(data, `${currentPath}/content/${i}`));
      }
    }
  }

  return textNodes;
};
import { set } from 'json-pointer';

import { combine } from './encode.js';
import { encodeRichTextValue } from './richText.js';
import type {
  CPAAsset,
  CPAEntry,
  CPAMappings,
  CreateSourceMapParams,
  FieldType,
  GraphQLMappings,
  GraphQLResponse,
  SourceMapMetadata,
  WidgetId,
  WidgetNamespace,
} from './types.js';

export const createSourceMapMetadata = ({
  entityId,
  entityType,
  space,
  environment,
  field,
  locale,
  editorInterface,
  fieldType,
  targetOrigin,
  platform,
}: CreateSourceMapParams): SourceMapMetadata => {
  const targetOriginUrl = targetOrigin || 'https://app.contentful.com';
  const basePath = `${targetOriginUrl}/spaces/${space}/environments/${environment}`;
  const entityRoute = entityType === 'Entry' ? 'entries' : 'assets';
  const href = `${basePath}/${entityRoute}/${entityId}/?focusedField=${field}&focusedLocale=${locale}&source=vercel-content-link`;

  const result: SourceMapMetadata = {
    origin: 'contentful.com',
    href,
    contentful: {
      editorInterface,
      fieldType,
    },
  };

  // If the user has specified a platform, we remove the fields that are not relevant to that platform
  if (platform === 'vercel') {
    delete result.contentful;
  }

  return result;
};

export const isBuiltinNamespace = (namespace: WidgetNamespace) =>
  ['builtin', 'sidebar-builtin', 'editor-builtin'].includes(namespace);
export const isSupportedWidget = (widgetId: WidgetId) => SUPPORTED_WIDGETS.includes(widgetId);

/**
 * Clones the incoming element into a new one, to prevent modification on the original object
 * Hint: It uses the structuredClone which is only available in modern browsers,
 * for older one it uses the JSON.parse(JSON.stringify) hack.
 */
export function clone<T extends Record<string, unknown> | Array<unknown>>(incoming: T): T {
  if (typeof structuredClone === 'function') {
    return structuredClone(incoming);
  }

  try {
    return JSON.parse(JSON.stringify(incoming));
  } catch (err) {
    console.warn('Failed to clone data:', incoming, err);
    return incoming;
  }
}

export const SUPPORTED_WIDGETS: WidgetId[] = [
  'singleLine',
  'tagEditor',
  'listInput',
  'checkbox',
  'richTextEditor',
  'multipleLine',
];

export function encodeField(
  fieldType: FieldType,
  currentValue: any,
  hiddenStrings: SourceMapMetadata,
  target: GraphQLResponse | CPAEntry | CPAAsset,
  pointer: string,
  mappings: CPAMappings | GraphQLMappings,
  locale?: string,
) {
  // Determine the value based on locale (if provided)
  const value = locale ? currentValue[locale] : currentValue;

  // Process based on fieldType
  switch (fieldType) {
    case 'Symbol': {
      const encodedValue = combine(value, hiddenStrings);
      set(target, pointer, encodedValue);
      break;
    }

    case 'Text': {
      const encodedValue = combine(value, hiddenStrings);
      set(target, pointer, encodedValue);
      break;
    }

    case 'RichText': {
      encodeRichTextValue({
        pointer: '',
        mappings,
        data: value,
        hiddenStrings,
      });
      break;
    }

    case 'Array': {
      const encodedArray = value.map((item: unknown) => {
        if (typeof item === 'string') {
          return combine(item, hiddenStrings);
        } else {
          return item; // Return the item unchanged if it's not a string
        }
      });
      set(target, pointer, encodedArray);
      break;
    }
  }
}
import { get, has } from 'json-pointer';

import type { CreateSourceMapParams } from '../types.js';
import {
  clone,
  createSourceMapMetadata,
  encodeField,
  isBuiltinNamespace,
  isSupportedWidget,
} from '../utils.js';

export const encodeGraphQLResponse = <TResponse extends { data: any; extensions: any }>(
  originalGraphqlResponse: TResponse,
  targetOrigin?: CreateSourceMapParams['targetOrigin'],
  platform?: CreateSourceMapParams['platform'],
): TResponse => {
  if (
    !originalGraphqlResponse ||
    !originalGraphqlResponse.extensions ||
    !originalGraphqlResponse.extensions.contentSourceMaps
  ) {
    console.error(
      'GraphQL response does not contain Content Source Maps information.',
      originalGraphqlResponse,
    );
    return originalGraphqlResponse;
  }
  const modifiedGraphqlResponse = clone(originalGraphqlResponse);
  const {
    spaces,
    environments,
    editorInterfaces,
    fields,
    locales,
    entries,
    assets,
    mappings,
    fieldTypes,
  } = modifiedGraphqlResponse.extensions.contentSourceMaps;
  const target = modifiedGraphqlResponse;

  for (const pointer in mappings) {
    const { source } = mappings[pointer];

    const entity = 'entry' in source ? entries[source.entry] : assets[source.asset];
    const entityType = 'entry' in source ? 'Entry' : 'Asset';

    if (!entity) {
      return modifiedGraphqlResponse;
    }

    const space = spaces[entity.space];
    const environment = environments[entity.environment];
    const entityId = entity.id;
    const field = fields[source.field];
    const locale = locales[source.locale];
    const editorInterface = editorInterfaces[source.editorInterface];
    const fieldType = fieldTypes[source.fieldType];

    // Skip unsupported widgets
    if (
      isBuiltinNamespace(editorInterface.widgetNamespace) &&
      !isSupportedWidget(editorInterface.widgetId)
    ) {
      continue;
    }

    if (has(target, pointer)) {
      const currentValue = get(target, pointer);

      if (currentValue !== null) {
        const hiddenStrings = createSourceMapMetadata({
          entityId,
          entityType,
          space,
          environment,
          field,
          locale,
          editorInterface,
          fieldType,
          targetOrigin,
          platform,
        });

        encodeField(fieldType, currentValue, hiddenStrings, target, pointer, mappings);
      }
    } else {
      //@TODO - add Sentry logging
      // console.warn(`Pointer ${pointer} not found in the entry`, target);
    }
  }
  return modifiedGraphqlResponse;
};
import { get, has } from 'json-pointer';

import type {
  CPAEntry,
  CPAEntryCollection,
  EditorInterfaceSource,
  FieldType,
  CreateSourceMapParams,
  CPAAsset,
} from '../types.js';
import {
  clone,
  createSourceMapMetadata,
  encodeField,
  isBuiltinNamespace,
  isSupportedWidget,
} from '../utils.js';

const applyEncoding = (
  target: CPAEntry | CPAAsset,
  fieldTypes: FieldType[],
  editorInterfaces: EditorInterfaceSource[],
  targetOrigin?: CreateSourceMapParams['targetOrigin'],
  platform?: CreateSourceMapParams['platform'],
) => {
  if (!target.fields) {
    return;
  }

  const { contentSourceMaps } = target.sys;

  // Skip if there are no source maps
  // For example if an entry has only one unsupported field
  if (!contentSourceMaps) {
    return;
  }

  const { mappings } = contentSourceMaps;

  for (const pointer in mappings) {
    const { source } = mappings[pointer];
    const space = target.sys.space.sys.id;
    const environment = target.sys.environment.sys.id;
    const entityId = target.sys.id;
    const entityType = target.sys.type;
    const fieldType = fieldTypes[source.fieldType];
    const editorInterface = editorInterfaces[source.editorInterface];

    // Skip unsupported widgets
    if (
      isBuiltinNamespace(editorInterface.widgetNamespace) &&
      !isSupportedWidget(editorInterface.widgetId)
    ) {
      continue;
    }

    const formattedPointer = pointer.startsWith('/') ? pointer : `/${pointer}`;

    if (has(target, formattedPointer)) {
      const currentValue = get(target, formattedPointer);
      if (currentValue === null) {
        return;
      }
      const fieldParts = formattedPointer.split('/'); // Split the pointer into parts
      const field = fieldParts.pop(); // Get the last part, which is the field name
      if (!field) {
        console.error('Field name could not be extracted from the pointer', formattedPointer);
        return;
      }
      const locale = target.sys.locale;

      // Determine if we are dealing with multiple locale values in the response or just a single locale
      if (locale) {
        const hiddenStrings = createSourceMapMetadata({
          entityId,
          entityType,
          space,
          environment,
          field,
          locale,
          editorInterface,
          fieldType,
          targetOrigin,
          platform,
        });

        encodeField(fieldType, currentValue, hiddenStrings, target, formattedPointer, mappings);
      } else {
        const locales = Object.keys(currentValue);
        locales.forEach((locale) => {
          const hiddenStrings = createSourceMapMetadata({
            entityId,
            entityType,
            space,
            environment,
            field,
            locale,
            editorInterface,
            fieldType,
            targetOrigin,
            platform,
          });

          encodeField(
            fieldType,
            currentValue,
            hiddenStrings,
            target,
            `${formattedPointer}/${locale}`,
            mappings,
            locale,
          );
        });
      }
    } else {
      //@TODO - add Sentry logging
      // console.warn(`Pointer ${pointer} not found in the entry`, target);
    }
  }
};

export const encodeCPAResponse = (
  CPAResponse: CPAEntry | CPAEntryCollection,
  targetOrigin?: CreateSourceMapParams['targetOrigin'],
  platform?: CreateSourceMapParams['platform'],
): CPAEntry | CPAEntryCollection => {
  const modifiedCPAResponse = clone(
    CPAResponse as unknown as Record<string, unknown>,
  ) as unknown as CPAEntry | CPAEntryCollection;

  // Entity collections
  if (modifiedCPAResponse.sys && 'items' in (modifiedCPAResponse as CPAEntryCollection)) {
    const collection = modifiedCPAResponse as CPAEntryCollection;
    if (!collection.sys?.contentSourceMapsLookup) {
      return collection;
    }
    const {
      contentSourceMapsLookup: { fieldTypes, editorInterfaces },
    } = collection.sys;
    const { items, includes } = collection;

    items.forEach((target) =>
      applyEncoding(target, fieldTypes, editorInterfaces, targetOrigin, platform),
    );
    if (includes && includes.Entry) {
      includes.Entry.forEach((entry) =>
        applyEncoding(entry, fieldTypes, editorInterfaces, targetOrigin, platform),
      );
    }
    if (includes && includes.Asset) {
      includes.Asset.forEach((asset) =>
        applyEncoding(asset, fieldTypes, editorInterfaces, targetOrigin, platform),
      );
    }
    // Single entity
  } else {
    const entry = modifiedCPAResponse as CPAEntry;
    if (!entry.sys.contentSourceMapsLookup) {
      console.error('Content source maps lookup data is missing');
      return entry;
    }

    applyEncoding(
      entry,
      entry.sys.contentSourceMapsLookup.fieldTypes,
      entry.sys.contentSourceMapsLookup.editorInterfaces,
      targetOrigin,
      platform,
    );
  }

  return modifiedCPAResponse;
};
